// Pair 1: execl (list) and execv (vector)
int execl(char* ref, char* argv0, ..., char* argvN, NULL);
int execv(char* ref, char* argv[]);
// N >= 1, i.e. argv0 and argvN can be omitted
// but the other arguments represent the effective
// command-line parameters for the program ref

// Pair 2: execle (list+env) and execve (vector+env)
int execle(char* ref, char* argv0, ..., char* argvN, char* env[]);
int execve(char* ref, char* argv[], char* env[]);
// env[] must also be NULL-terminated

// Pair 3: execlp (list+PATH) and execvp (vector+PATH)
int execlp(char* ref, char* argv0, ..., char* argvN);
int execvp(char* ref, char* argv[]);

// 7th function (GNU extension): execvpe (vector+PATH+env)
int execvpe(char* ref, char* argv[], char* env[]);

/* before_exec.c */
#include <stdio.h>
#include <unistd.h>
#include <fcntl.h>

int main() {
    int fd;
    char buf[100];
    int nrBytesRead;

    printf("[before_exec] PID = %d\n", getpid());

    /* Read from stdin */
    nrBytesRead = read(0, buf, sizeof(buf));
    printf("[before_exec] Read %d bytes from stdin\n", nrBytesRead);

    /* Overlay with after_exec */
    execl("./after_exec", "after_exec", NULL);

    /* Only reached if exec fails */
    perror("exec failed");
    return 1;
}

