/* exec_rec.c - Recursive overlay example */
#include <stdio.h>
#include <string.h>
#include <unistd.h>

int main(int argc, char *argv[]) {
    printf("[exec_rec] PID=%d, argc=%d\n", getpid(), argc);

    if (argc == 1) {
        /* First call: overlay with self, adding an argument */
        printf("[exec_rec] First call, overlaying with self...\n");
        execl("./exec_rec", "exec_rec", "second", NULL);
        perror("exec failed");
    } else {
        /* Second call: detected by extra argument */
        printf("[exec_rec] Second call (arg: %s), stopping.\n", argv[1]);
    }
    return 0;
}

/* redirect.c - Redirecting stdout to a file and back */
#include <stdio.h>
#include <unistd.h>
#include <fcntl.h>

int main() {
    int fd, saved_stdout;

    /* Save stdout */
    saved_stdout = dup(1);

    /* Open file and redirect stdout to it */
    fd = open("fis.txt", O_WRONLY | O_CREAT | O_TRUNC, 0644);
    dup2(fd, 1);  /* fd 1 (stdout) now points to fis.txt */
    close(fd);

    printf("This goes to fis.txt\n");
    fflush(stdout);

    /* Restore stdout to terminal */
    dup2(saved_stdout, 1);
    close(saved_stdout);

    printf("This goes to the terminal\n");
    return 0;
}

