#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/wait.h>

int main(int argc, char *argv[]) {
    pid_t pid;
    int ret;
    char* dirname = (argc < 2) ? "." : argv[1];

    /* Create a child process to run the command via exec */
    if (-1 == (pid = fork())) {
        perror("Error at fork");
        exit(1);
    }

    if (pid == 0) {
        /* Child: exec the ls command */
        execl("/bin/ls", "ls", "-l", "-i", dirname, NULL);
        perror("Error at exec");
        exit(10);  /* Return a large number as error code */
    }

    /* Parent: wait for the child */
    wait(&ret);
    if (WIFEXITED(ret)) {
        switch (WEXITSTATUS(ret)) {
            case 10: printf("ls could not be executed (exec error).\n"); break;
            case  0: printf("ls executed successfully.\n"); break;
            default: printf("ls failed (code: %d).\n", WEXITSTATUS(ret));
        }
    } else {
        printf("ls was terminated by signal: %d.\n", WTERMSIG(ret));
    }
    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main(int argc, char *argv[]) {
    int ret;
    char *dirname = (argc < 2) ? "." : argv[1];

    /* Build command string */
    char cmdline[256];
    sprintf(cmdline, "ls -l -a %s ; ls -a %s", dirname, dirname);

    /* Execute via system() */
    ret = system(cmdline);
    printf("system() returned: %d\n", ret);

    return 0;
}
